import numpy as np
import cv2
from astropy.io import fits


def apply_radial_distortion(centers, k):
    """
    Aplica distorsión radial a una lista de centros.
    centers: array Nx2 de (x, y)
    k_coeffs: lista de coeficientes [k1, k2, ...]
    """
    distorted = []
    for x, y in centers:
        x = x - 4096/2
        y = y - 3072/2
        r = np.sqrt(x**2 + y**2)
        factor = 1 + k * (r ** 2)
        distorted.append([x*factor + 4096/2, y*factor + 3072/2])

    return np.array(distorted)

def draw_centers(ideal_centers, distorted_centers, output_path):
    """
    Dibuja centros ideales y distorsionados sobre la imagen FITS.
    """
    #Crea una imagen negra en BGR.
    img_color = np.zeros((3072, 4096, 3), dtype=np.uint8)

    # Dibujar centros distorsionados (rojo)
    for c in ideal_centers:
        x, y = int(c[0]), int(c[1])
        cv2.circle(img_color, (x, y), 6, (0, 0, 255), -1)
        
    # Dibujar centros ideales (blanco)
    for c in distorted_centers:
        x, y = int(c[0]), int(c[1])
        cv2.circle(img_color, (x, y), 6, (255, 255, 255), -1)  # -1 = relleno
            
    cv2.imwrite(output_path, img_color)
    print(f"Imagen guardada en {output_path}")

